				return err
			}
			newSourceStateEntry, err = s.sourceStateEntry(actualStateEntry, destAbsPath, destAbsPathInfo, parentSourceRelPath, targetRelPath, options)
			if err != nil {
				return err
			}
			if newSourceStateEntry == nil {
